"use client"

import * as React from "react"
import { cn } from "@/lib/utils"

export function dataWorkspaceTypeBadgeClassName(type?: string): string {
  const normalizedType = (type ?? "text").toLowerCase()

  if (normalizedType === "enum" || normalizedType === "select") {
    return "border-amber-300/60 bg-amber-500/10 text-amber-700 dark:text-amber-300"
  }

  if (normalizedType === "uuid" || normalizedType === "foreign-key" || normalizedType === "link") {
    return "border-sky-300/60 bg-sky-500/10 text-sky-700 dark:text-sky-300"
  }

  if (normalizedType === "datetime" || normalizedType === "date") {
    return "border-violet-300/60 bg-violet-500/10 text-violet-700 dark:text-violet-300"
  }

  if (normalizedType === "boolean") {
    return "border-emerald-300/60 bg-emerald-500/10 text-emerald-700 dark:text-emerald-300"
  }

  if (normalizedType === "json") {
    return "border-rose-300/60 bg-rose-500/10 text-rose-700 dark:text-rose-300"
  }

  return "border-border/70 bg-muted/45 text-muted-foreground"
}

export function dataWorkspaceMetaBadgeClassName(tone: "default" | "primary" | "success" | "danger" = "default"): string {
  if (tone === "primary") {
    return "border-border/70 bg-foreground/[0.06] text-foreground"
  }

  if (tone === "success") {
    return "border-emerald-300/60 bg-emerald-500/10 text-emerald-700 dark:text-emerald-300"
  }

  if (tone === "danger") {
    return "border-destructive/25 bg-destructive/10 text-destructive"
  }

  return "border-border/70 bg-background/70 text-muted-foreground"
}

export function dataWorkspaceRelationBadgeClassName(source?: string): string {
  if (source === "base") {
    return "border-border/70 bg-background/80 text-foreground"
  }

  return "border-border/70 bg-muted/50 text-muted-foreground"
}

export function dataWorkspaceRowClassName(options?: {
  interactive?: boolean
  selected?: boolean
}): string {
  return cn(
    "group border-b transition-colors",
    options?.interactive && "cursor-pointer hover:bg-muted/50",
    options?.selected && "bg-muted hover:bg-muted/70",
  )
}

export interface DataWorkspaceHeaderProps {
  eyebrow?: React.ReactNode
  title: React.ReactNode
  description?: React.ReactNode
  meta?: React.ReactNode
  actions?: React.ReactNode
  className?: string
}

export function DataWorkspaceHeader({
  eyebrow,
  title,
  description,
  meta,
  actions,
  className,
}: DataWorkspaceHeaderProps) {
  return (
    <div className={cn("flex flex-col gap-1.5 sm:flex-row sm:items-center sm:justify-between", className)}>
      <div className="min-w-0 space-y-1">
        <div className="space-y-1">
          {eyebrow ? (
            <p className="text-xs font-medium text-muted-foreground">
              {eyebrow}
            </p>
          ) : null}
          <h3 className="text-lg font-semibold leading-none tracking-tight">
            {title}
          </h3>
          {description ? (
            <p className="text-sm text-muted-foreground">
              {description}
            </p>
          ) : null}
        </div>
        {meta ? (
          <div className="flex flex-wrap items-center gap-1.5 text-xs text-muted-foreground pt-1">
            {meta}
          </div>
        ) : null}
      </div>
      {actions ? (
        <div className="flex shrink-0 flex-wrap items-center gap-2">
          {actions}
        </div>
      ) : null}
    </div>
  )
}

type DataStateTone = "neutral" | "danger" | "success"

export interface DataWorkspaceStateProps extends React.HTMLAttributes<HTMLDivElement> {
  tone?: DataStateTone
  heading?: React.ReactNode
  description: React.ReactNode
}

export function DataWorkspaceState({
  tone = "neutral",
  heading,
  description,
  className,
  ...props
}: DataWorkspaceStateProps) {
  return (
    <div
      className={cn(
        "rounded-lg border p-4 text-sm",
        tone === "danger" && "border-destructive/50 bg-destructive/10 text-destructive",
        tone === "success" && "border-emerald-500/30 bg-emerald-500/10 text-emerald-700 dark:text-emerald-300",
        tone === "neutral" && "border-dashed text-muted-foreground",
        className,
      )}
      {...props}
    >
      <div className="grid gap-1">
        {heading ? (
          <p className="font-medium text-foreground">{heading}</p>
        ) : null}
        <div className={tone === "neutral" ? "text-muted-foreground" : undefined}>
          {description}
        </div>
      </div>
    </div>
  )
}

"use client"

import * as React from "react"
import type { JsonSchemaLike } from "lemma-sdk"
import { useSchemaForm } from "lemma-sdk/react"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardHeader } from "@/components/ui/card"
import { Checkbox } from "@/components/ui/checkbox"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { Textarea } from "@/components/ui/textarea"
import {
  DataWorkspaceHeader,
  DataWorkspaceState,
  dataWorkspaceTypeBadgeClassName,
} from "@/components/lemma/registry-data-workspace"
import { cn } from "@/lib/utils"

export interface LemmaSchemaFormProps extends Omit<React.HTMLAttributes<HTMLDivElement>, "onSubmit"> {
  schema?: JsonSchemaLike | null
  uiSchema?: Record<string, unknown> | null
  initialValues?: Record<string, unknown>
  title?: string
  description?: string
  submitLabel?: string
  disabled?: boolean
  onSubmit?: (data: Record<string, unknown>) => Promise<void> | void
  onSubmitted?: (data: Record<string, unknown>) => void
  showReset?: boolean
  resetLabel?: string
  hiddenFields?: string[]
  fieldLabels?: Record<string, string>
  fieldDescriptions?: Record<string, string>
}

function schemaFieldType(kind: string): string {
  if (kind === "select") return "select"
  if (kind === "boolean") return "boolean"
  if (kind === "json") return "json"
  if (kind === "number") return "number"
  if (kind === "date") return "date"
  if (kind === "datetime") return "datetime"
  if (kind === "email") return "text"
  return "text"
}

export const LemmaSchemaForm = React.forwardRef<HTMLDivElement, LemmaSchemaFormProps>(
  ({
    schema,
    uiSchema,
    initialValues,
    title = "Schema Form",
    description = "Generated from JSON Schema.",
    submitLabel = "Submit",
    disabled = false,
    onSubmit,
    onSubmitted,
    showReset = true,
    resetLabel = "Reset",
    hiddenFields = [],
    fieldLabels,
    fieldDescriptions,
    className,
    ...props
  }, ref) => {
  const form = useSchemaForm({
    schema,
    uiSchema,
    initialValues,
    onSubmit: async (data) => {
      await onSubmit?.(data)
      onSubmitted?.(data)
    },
  })

  const hasFields = form.fields.length > 0
  const visibleFields = form.fields.filter((field) => !hiddenFields.includes(field.name))

  const handleSubmit = React.useCallback(async (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault()
    await form.submit()
  }, [form])

  const meta = hasFields ? (
    <Badge
      className={cn("rounded-full border px-2 py-0.5 text-xs", "border-border/70 bg-background/70 text-muted-foreground")}
      variant="outline"
    >
      {visibleFields.length} field{visibleFields.length === 1 ? "" : "s"}
    </Badge>
  ) : null

  return (
    <div ref={ref} className={cn("rounded-lg border bg-card text-card-foreground shadow-sm", className)} {...props}>
      <CardHeader className="p-6">
        <DataWorkspaceHeader
          description={description}
          meta={meta}
          title={title}
        />
      </CardHeader>
      <CardContent className="p-6 pt-0">
        <form className="grid gap-5" onSubmit={handleSubmit}>
          {form.error ? (
            <DataWorkspaceState description={form.error.message} heading="Submission failed" tone="danger" />
          ) : null}

          {!hasFields ? (
            <DataWorkspaceState description="This schema does not define any editable fields." />
          ) : null}

          {visibleFields.map((field) => {
            const value = form.values[field.name]
            const error = form.fieldErrors[field.name]
            const resolvedLabel = fieldLabels?.[field.name] ?? field.label
            const resolvedDescription = fieldDescriptions?.[field.name] ?? field.description
            const fieldBadge = (
              <Badge
                className={cn("rounded-full border px-2 py-0.5 text-xs", dataWorkspaceTypeBadgeClassName(schemaFieldType(field.kind)))}
                variant="outline"
              >
                {field.kind}
              </Badge>
            )
            const fieldLabel = (
              <div className="flex flex-wrap items-center gap-3">
                <Label className="text-sm font-medium text-muted-foreground" htmlFor={field.name}>
                  {resolvedLabel}
                  {field.required ? " *" : ""}
                </Label>
                {fieldBadge}
              </div>
            )

            if (field.kind === "boolean") {
              return (
                <div key={field.name} className="rounded-lg border bg-muted/50 p-4 grid gap-3">
                  {fieldLabel}
                  {resolvedDescription ? (
                    <p className="text-sm leading-6 text-muted-foreground">{resolvedDescription}</p>
                  ) : null}
                  <label className="flex items-center gap-3 text-sm">
                    <Checkbox
                      checked={Boolean(value)}
                      onCheckedChange={(checked) => form.setValue(field.name, checked === true)}
                    />
                    <span className="font-medium text-foreground">{Boolean(value) ? "Enabled" : "Disabled"}</span>
                  </label>
                  {error ? <p className="text-sm text-destructive">{error}</p> : null}
                </div>
              )
            }

            if (field.kind === "select") {
              return (
                <div key={field.name} className="grid gap-2">
                  {fieldLabel}
                  {resolvedDescription ? (
                    <p className="text-sm leading-6 text-muted-foreground">{resolvedDescription}</p>
                  ) : null}
                  <Select
                    value={typeof value === "string" ? value : ""}
                    onValueChange={(nextValue) => form.setValue(field.name, nextValue)}
                  >
                    <SelectTrigger className="h-10" id={field.name}>
                      <SelectValue placeholder={`Select ${field.label.toLowerCase()}`} />
                    </SelectTrigger>
                    <SelectContent>
                      {field.options.map((option) => (
                        <SelectItem key={option.value} value={option.value}>
                          {option.label}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                  {error ? <p className="text-sm text-destructive">{error}</p> : null}
                </div>
              )
            }

            if (field.kind === "json" || field.kind === "textarea") {
              return (
                <div key={field.name} className="grid gap-2">
                  {fieldLabel}
                  {resolvedDescription ? (
                    <p className="text-sm leading-6 text-muted-foreground">{resolvedDescription}</p>
                  ) : null}
                  <Textarea
                    className="min-h-24"
                    id={field.name}
                    rows={field.kind === "json" ? 8 : 4}
                    value={typeof value === "string" ? value : ""}
                    onChange={(event) => form.setValue(field.name, event.target.value)}
                  />
                  {error ? <p className="text-sm text-destructive">{error}</p> : null}
                </div>
              )
            }

            return (
              <div key={field.name} className="grid gap-2">
                {fieldLabel}
                {resolvedDescription ? (
                  <p className="text-sm leading-6 text-muted-foreground">{resolvedDescription}</p>
                ) : null}
                <Input
                  className="h-10"
                  id={field.name}
                  type={
                    field.kind === "number"
                      ? "number"
                      : field.kind === "date"
                        ? "date"
                        : field.kind === "datetime"
                          ? "datetime-local"
                          : field.kind === "email"
                            ? "email"
                            : "text"
                  }
                  value={typeof value === "string" ? value : value ? String(value) : ""}
                  onChange={(event) => form.setValue(field.name, event.target.value)}
                />
                {error ? <p className="text-sm text-destructive">{error}</p> : null}
              </div>
            )
          })}

          <div className="flex flex-wrap items-center justify-end gap-3 border-t border-border/60 pt-5">
            {showReset ? (
              <Button
                disabled={disabled || form.isSubmitting}
                onClick={() => form.reset()}
                type="button"
                variant="outline"
              >
                {resetLabel}
              </Button>
            ) : null}
            <Button
              disabled={disabled || form.isSubmitting}
              type="submit"
            >
              {form.isSubmitting ? "Submitting\u2026" : submitLabel}
            </Button>
          </div>
        </form>
      </CardContent>
    </div>
  )
})
LemmaSchemaForm.displayName = "LemmaSchemaForm"

"use client"

import * as React from "react"
import type { Task } from "lemma-sdk"
import { Card, CardContent, CardHeader } from "@/components/ui/card"
import {
  DataWorkspaceHeader,
  DataWorkspaceState,
} from "@/components/lemma/registry-data-workspace"
import { cn } from "@/lib/utils"

export interface LemmaAgentOutputCardProps extends React.HTMLAttributes<HTMLDivElement> {
  task?: Task | null
  output?: Record<string, unknown> | unknown[] | string | null
  finalOnly?: boolean
  title?: string
  description?: string
  emptyText?: string
}

function formatJson(value: unknown): string {
  if (value === null || typeof value === "undefined") return ""
  if (typeof value === "string") return value
  try {
    return JSON.stringify(value, null, 2)
  } catch {
    return String(value)
  }
}

export const LemmaAgentOutputCard = React.forwardRef<HTMLDivElement, LemmaAgentOutputCardProps>(
  ({
    task,
    output,
    finalOnly = false,
    title = "Agent Output",
    description = "Inspect the latest structured output from the selected task.",
    emptyText = "Run an agent to inspect output here.",
    className,
    ...props
  }, ref) => {
  const isFinal = task?.status === "COMPLETED" || task?.status === "FAILED" || task?.status === "CANCELLED" || task?.status === "STOPPED"
  const resolvedOutput = typeof output === "undefined" ? task?.output_data : output
  const visibleOutput = finalOnly && !isFinal ? null : resolvedOutput

  return (
    <div ref={ref} className={cn("rounded-lg border bg-card text-card-foreground shadow-sm", className)} {...props}>
      <CardHeader className="p-6">
        <DataWorkspaceHeader description={description} title={title} />
      </CardHeader>
      <CardContent className="p-6 pt-0">
        <div className="flex flex-col gap-4">
          {task ? (
            <div className="rounded-lg border bg-muted/50 p-4 grid gap-2 text-sm">
              <div className="font-medium">Status: {task.status}</div>
              <div className="truncate text-sm text-muted-foreground">Task ID: {task.id}</div>
            </div>
          ) : null}
          {visibleOutput ? (
            <pre className="rounded-lg border bg-muted/50 p-4 overflow-x-auto whitespace-pre-wrap text-sm">
              {formatJson(visibleOutput)}
            </pre>
          ) : (
            <DataWorkspaceState description={emptyText} />
          )}
        </div>
      </CardContent>
    </div>
  )
})
LemmaAgentOutputCard.displayName = "LemmaAgentOutputCard"

"use client"

import * as React from "react"
import type { LemmaClient } from "lemma-sdk"
import { useAgentRun } from "lemma-sdk/react"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardHeader } from "@/components/ui/card"
import {
  DataWorkspaceHeader,
  DataWorkspaceState,
} from "@/components/lemma/registry-data-workspace"
import { cn } from "@/lib/utils"

export interface LemmaAgentMessagesProps extends React.HTMLAttributes<HTMLDivElement> {
  client: LemmaClient
  podId?: string
  taskId?: string | null
  title?: string
  description?: string
}

function formatContent(value: unknown): string {
  if (typeof value === "string") return value
  if (value === null || typeof value === "undefined") return ""
  try {
    return JSON.stringify(value, null, 2)
  } catch {
    return String(value)
  }
}

export const LemmaAgentMessages = React.forwardRef<HTMLDivElement, LemmaAgentMessagesProps>(
  ({
    client,
    podId,
    taskId,
    title = "Agent Messages",
    description = "Task messages streamed or loaded from the selected agent run.",
    className,
    ...props
  }, ref) => {
  const run = useAgentRun({
    client,
    podId,
    taskId,
    autoConnect: false,
  })

  const actions = (
    <Button
      disabled={!taskId}
      onClick={() => {
        void run.loadMessages(taskId)
      }}
      type="button"
      variant="outline"
    >
      Refresh
    </Button>
  )

  return (
    <div ref={ref} className={cn("rounded-lg border bg-card text-card-foreground shadow-sm", className)} {...props}>
      <CardHeader className="p-6">
        <DataWorkspaceHeader
          actions={actions}
          description={description}
          title={title}
        />
      </CardHeader>
      <CardContent className="p-6 pt-0">
        <div className="flex flex-col gap-4">
          {run.error ? (
            <DataWorkspaceState description={run.error.message} heading="Failed to load messages" tone="danger" />
          ) : null}
          {!taskId ? (
            <DataWorkspaceState description="Select or start an agent run to load messages." />
          ) : run.messages.length === 0 ? (
            <DataWorkspaceState description="No messages loaded for this run." />
          ) : (
            run.messages.map((message) => (
              <div key={message.id} className="rounded-lg border bg-muted/50 p-4">
                <div className="mb-2 text-[11px] font-semibold uppercase tracking-[0.14em] text-muted-foreground">
                  {message.role ?? "message"}
                </div>
                <pre className="whitespace-pre-wrap text-sm leading-6">
                  {formatContent(message.content)}
                </pre>
              </div>
            ))
          )}
        </div>
      </CardContent>
    </div>
  )
})
LemmaAgentMessages.displayName = "LemmaAgentMessages"

"use client"

import * as React from "react"
import type { JsonSchemaLike, LemmaClient, Task } from "lemma-sdk"
import { useAgentInputSchema, useAgentRun } from "lemma-sdk/react"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardHeader } from "@/components/ui/card"
import { Label } from "@/components/ui/label"
import { Textarea } from "@/components/ui/textarea"
import { LemmaAgentMessages } from "@/components/lemma/lemma-agent-messages"
import { LemmaAgentOutputCard } from "@/components/lemma/lemma-agent-output-card"
import { LemmaSchemaForm } from "@/components/lemma/lemma-schema-form"
import {
  DataWorkspaceHeader,
  DataWorkspaceState,
} from "@/components/lemma/registry-data-workspace"
import { cn } from "@/lib/utils"

export interface LemmaAgentRunPanelProps extends Omit<React.HTMLAttributes<HTMLDivElement>, "onError"> {
  client: LemmaClient
  podId?: string
  agentName: string
  inputSchema?: JsonSchemaLike | null
  title?: string
  description?: string
  onStarted?: (task: Task) => void
  onError?: (error: Error) => void
}

export const LemmaAgentRunPanel = React.forwardRef<HTMLDivElement, LemmaAgentRunPanelProps>(
  ({
    client,
    podId,
    agentName,
    inputSchema,
    title = "Agent Runner",
    description = "Start an agent with schema-aware input, then inspect status, output, and messages.",
    onStarted,
    onError,
    className,
    ...props
  }, ref) => {
  const [followUp, setFollowUp] = React.useState("")
  const [followUpError, setFollowUpError] = React.useState<string | null>(null)
  const schemaState = useAgentInputSchema({
    client,
    podId,
    agentName,
    enabled: !!agentName && !inputSchema,
  })
  const run = useAgentRun({
    client,
    podId,
    agentName: agentName || undefined,
    autoConnect: true,
    autoConnectOnStart: true,
  })
  const schema = inputSchema ?? schemaState.inputSchema

  React.useEffect(() => {
    if (schemaState.error) {
      onError?.(schemaState.error)
    }
  }, [schemaState.error, onError])

  React.useEffect(() => {
    if (run.error) {
      onError?.(run.error)
    }
  }, [run.error, onError])

  return (
    <div ref={ref} className={cn("grid gap-4", className)} {...props}>
      <Card>
        <CardHeader className="p-6">
          <DataWorkspaceHeader description={description} title={title} />
        </CardHeader>
        <CardContent className="p-6 pt-0">
          <div className="flex flex-col gap-4">
            {schemaState.error ? (
              <DataWorkspaceState description={schemaState.error.message} heading="Schema error" tone="danger" />
            ) : null}
            {run.error ? (
              <DataWorkspaceState description={run.error.message} heading="Run error" tone="danger" />
            ) : null}
            <div className="grid gap-4 sm:grid-cols-2">
              <div className="rounded-lg border bg-muted/50 p-4 text-sm">
                <div className="text-[11px] font-semibold uppercase tracking-[0.14em] text-muted-foreground">Status</div>
                <div className="font-medium">{run.status ?? "idle"}</div>
              </div>
              <div className="rounded-lg border bg-muted/50 p-4 text-sm">
                <div className="text-[11px] font-semibold uppercase tracking-[0.14em] text-muted-foreground">Task ID</div>
                <div className="truncate font-medium">{run.taskId ?? "none"}</div>
              </div>
            </div>
          </div>
        </CardContent>
      </Card>

      <LemmaSchemaForm
        disabled={!agentName || run.isStreaming}
        description={schemaState.isLoading ? "Loading agent input schema\u2026" : "Submit structured input to start this agent."}
        onSubmit={async (data) => {
          const task = await run.start(data)
          onStarted?.(task)
        }}
        schema={schema}
        submitLabel={run.isStreaming ? "Running\u2026" : "Run agent"}
        title={agentName ? `Input: ${agentName}` : "Agent Input"}
      />

      {run.isWaitingForInput ? (
        <Card>
          <CardHeader className="p-6">
            <DataWorkspaceHeader
              description="This run is waiting for a response before it can continue."
              title="Follow-up Input"
            />
          </CardHeader>
          <CardContent className="p-6 pt-0">
            <div className="flex flex-col gap-4">
              {followUpError ? (
                <DataWorkspaceState description={followUpError} heading="Failed to submit" tone="danger" />
              ) : null}
              <div className="grid gap-2">
                <Label className="text-[11px] font-semibold uppercase tracking-[0.14em] text-muted-foreground" htmlFor="lemma-agent-follow-up">
                  Response
                </Label>
                <Textarea
                  className="min-h-24"
                  id="lemma-agent-follow-up"
                  onChange={(event) => setFollowUp(event.target.value)}
                  rows={4}
                  value={followUp}
                />
              </div>
              <Button
                disabled={!followUp.trim()}
                onClick={async () => {
                  setFollowUpError(null)
                  try {
                    await run.submitInput(followUp)
                    setFollowUp("")
                  } catch (error) {
                    const errorMsg = error instanceof Error ? error.message : "Failed to submit follow-up input."
                    setFollowUpError(errorMsg)
                    onError?.(error instanceof Error ? error : new Error(errorMsg))
                  }
                }}
              >
                Submit response
              </Button>
            </div>
          </CardContent>
        </Card>
      ) : null}

      <LemmaAgentOutputCard task={run.task} />
      <LemmaAgentMessages client={client} podId={podId} taskId={run.taskId} />
    </div>
  )
})
LemmaAgentRunPanel.displayName = "LemmaAgentRunPanel"
